mapper.select:
select orders.*, user.name as userName from `orders` left join `user` on orders.user_id = user.id
and orders.order_no like concat('%', #{orderNo}, '%') and orders.user_id = #{userId}
order by orders.id desc

mapper.update:
update `orders` set order_no = #{orderNo}, rel_id = #{relId}, num = #{num}, price = #{price},
                  time = #{time}, status = #{status}, phone = #{phone}, address = #{address}, user_id = #{userId}
where id = #{id}
